from flask import Flask, request, jsonify
from functools import wraps
import secrets
import hashlib
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-in-production'

# In-memory storage (use a database in production)
users_db = {
    'admin': {
        'password_hash': hashlib.sha256('admin123'.encode()).hexdigest(),
        'name': 'Admin User'
    },
    'john': {
        'password_hash': hashlib.sha256('john123'.encode()).hexdigest(),
        'name': 'John Doe'
    }
}

# Token storage: token -> {username, created_at, expires_at}
tokens_db = {}


def generate_token():
    """Generate a secure random token."""
    return secrets.token_hex(32)


def hash_password(password):
    """Hash a password using SHA-256."""
    return hashlib.sha256(password.encode()).hexdigest()


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check for token in Authorization header
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            if auth_header.startswith('Bearer '):
                token = auth_header.split(' ')[1]

        # Also check query parameter as fallback
        if not token:
            token = request.args.get('token')

        if not token:
            return jsonify({
                'success': False,
                'message': 'Token is missing. Please provide a valid token.'
            }), 401

        # Validate token
        token_data = tokens_db.get(token)
        if not token_data:
            return jsonify({
                'success': False,
                'message': 'Token is invalid.'
            }), 401

        # Check if token has expired
        if datetime.datetime.utcnow() > token_data['expires_at']:
            # Remove expired token
            del tokens_db[token]
            return jsonify({
                'success': False,
                'message': 'Token has expired. Please login again.'
            }), 401

        # Pass current user info to the route
        current_user = {
            'username': token_data['username'],
            'name': users_db[token_data['username']]['name']
        }

        return f(current_user, *args, **kwargs)

    return decorated


@app.route('/', methods=['GET'])
def home():
    """Public endpoint - no authentication required."""
    return jsonify({
        'success': True,
        'message': 'Welcome to the API Authentication System',
        'endpoints': {
            'POST /register': 'Register a new user',
            'POST /login': 'Login and get a token',
            'POST /logout': 'Logout and invalidate token',
            'GET /protected': 'Protected endpoint (requires token)',
            'GET /profile': 'Get user profile (requires token)',
            'GET /users': 'List all users (requires token)',
        }
    })


@app.route('/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    username = data.get('username')
    password = data.get('password')
    name = data.get('name', '')

    if not username or not password:
        return jsonify({
            'success': False,
            'message': 'Username and password are required.'
        }), 400

    if len(password) < 6:
        return jsonify({
            'success': False,
            'message': 'Password must be at least 6 characters long.'
        }), 400

    if username in users_db:
        return jsonify({
            'success': False,
            'message': 'Username already exists.'
        }), 409

    users_db[username] = {
        'password_hash': hash_password(password),
        'name': name or username
    }

    return jsonify({
        'success': True,
        'message': f'User "{username}" registered successfully.'
    }), 201


@app.route('/login', methods=['POST'])
def login():
    """Authenticate user and return a token."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({
            'success': False,
            'message': 'Username and password are required.'
        }), 400

    # Verify user exists
    user = users_db.get(username)
    if not user:
        return jsonify({
            'success': False,
            'message': 'Invalid username or password.'
        }), 401

    # Verify password
    if user['password_hash'] != hash_password(password):
        return jsonify({
            'success': False,
            'message': 'Invalid username or password.'
        }), 401

    # Generate token
    token = generate_token()
    expiration = datetime.datetime.utcnow() + datetime.timedelta(hours=24)

    tokens_db[token] = {
        'username': username,
        'created_at': datetime.datetime.utcnow(),
        'expires_at': expiration
    }

    return jsonify({
        'success': True,
        'message': 'Login successful.',
        'data': {
            'token': token,
            'token_type': 'Bearer',
            'expires_at': expiration.isoformat(),
            'user': {
                'username': username,
                'name': user['name']
            }
        }
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(current_user):
    """Invalidate the current token (logout)."""
    # Find and remove the token
    auth_header = request.headers.get('Authorization', '')
    token = None
    if auth_header.startswith('Bearer '):
        token = auth_header.split(' ')[1]
    if not token:
        token = request.args.get('token')

    if token and token in tokens_db:
        del tokens_db[token]

    return jsonify({
        'success': True,
        'message': 'Logged out successfully. Token has been invalidated.'
    }), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected(current_user):
    """A protected endpoint that requires authentication."""
    return jsonify({
        'success': True,
        'message': 'You have access to this protected endpoint!',
        'data': {
            'current_user': current_user,
            'secret_info': 'This is confidential data only for authenticated users.'
        }
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile(current_user):
    """Get the profile of the currently authenticated user."""
    username = current_user['username']
    user_data = users_db.get(username, {})

    return jsonify({
        'success': True,
        'data': {
            'username': username,
            'name': user_data.get('name', ''),
        }
    }), 200


@app.route('/profile', methods=['PUT'])
@token_required
def update_profile(current_user):
    """Update the profile of the currently authenticated user."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    username = current_user['username']

    if 'name' in data:
        users_db[username]['name'] = data['name']

    if 'password' in data:
        if len(data['password']) < 6:
            return jsonify({
                'success': False,
                'message': 'Password must be at least 6 characters long.'
            }), 400
        users_db[username]['password_hash'] = hash_password(data['password'])

    return jsonify({
        'success': True,
        'message': 'Profile updated successfully.',
        'data': {
            'username': username,
            'name': users_db[username]['name']
        }
    }), 200


@app.route('/users', methods=['GET'])
@token_required
def list_users(current_user):
    """List all registered users (requires authentication)."""
    user_list = []
    for username, user_data in users_db.items():
        user_list.append({
            'username': username,
            'name': user_data['name']
        })

    return jsonify({
        'success': True,
        'data': {
            'users': user_list,
            'total': len(user_list)
        }
    }), 200


@app.route('/tokens/cleanup', methods=['POST'])
@token_required
def cleanup_tokens(current_user):
    """Remove all expired tokens."""
    now = datetime.datetime.utcnow()
    expired_tokens = [
        token for token, data in tokens_db.items()
        if now > data['expires_at']
    ]

    for token in expired_tokens:
        del tokens_db[token]

    return jsonify({
        'success': True,
        'message': f'Cleaned up {len(expired_tokens)} expired tokens.',
        'data': {
            'removed': len(expired_tokens),
            'active_tokens': len(tokens_db)
        }
    }), 200


